await page.evaluate('
() => {
  function norm(s){ return (s||"").replace(/\s+/g," ").trim(); }
  function visible(el){
    if (!el) return false;
    const style = window.getComputedStyle(el);
    const r = el.getBoundingClientRect();
    return style.visibility !== 'hidden' && style.display !== 'none' && r.width>0 && r.height>0;
  }
  function textOf(el){ return norm(el?.innerText || el?.textContent || ""); }
  function roleOf(el){
    const r = el.getAttribute('role');
    if (r) return r;
    const tag = (el.tagName||"").toLowerCase();
    if (tag === "a") return "link";
    if (tag === "button") return "button";
    if (tag === "input") {
      const t = (el.getAttribute("type")||"").toLowerCase();
      if (t === "checkbox") return "checkbox";
      if (t === "password" || t === "text" || t === "email") return "textbox";
    }
    return null;
  }
  function labelTextForInput(input){
    if (!input) return "";
    const id = input.id;
    if (id) {
      const lab = document.querySelector('label[for="'+CSS.escape(id)+'"]');
      if (lab) return textOf(lab);
    }
    let p = input.parentElement;
    for (let i=0;i<3 && p;i++){
      if (p.tagName && p.tagName.toLowerCase()==='label') return textOf(p);
      p = p.parentElement;
    }
    return "";
  }
  function toMatch(el){
    if (!el) return null;
    const tag = (el.tagName||"").toLowerCase();
    const type = (el.getAttribute("type")||"").toLowerCase();
    const role = roleOf(el);
    const text = textOf(el);
    const testid = el.getAttribute("data-testid") || el.getAttribute("data-test-id") || el.getAttribute("data-test");
    const ariaLabel = el.getAttribute("aria-label") || el.getAttribute("title");
    const id = el.id || null;
    const nameAttr = el.getAttribute("name") || null;
    const labelText = tag === "input" ? labelTextForInput(el) : "";
    return { tag, type, role, text, testid, ariaLabel, id, nameAttr, labelText };
  }
  function findByTextRegex(selectors, regex){
    const els = Array.from(document.querySelectorAll(selectors)).filter(visible);
    for (const el of els){
      const t = textOf(el);
      if (regex.test(t)) return el;
      const aria = el.getAttribute("aria-label") || el.getAttribute("title") || "";
      if (regex.test(aria)) return el;
    }
    return null;
  }

  const forgot = findByTextRegex('a,button,[role="link"],[role="button"]', /forgot\s+password|reset\s+password/i);

  let remember = null;
  const checkboxes = Array.from(document.querySelectorAll('input[type="checkbox"],[role="checkbox"]')).filter(visible);
  for (const cb of checkboxes){
    const lab = labelTextForInput(cb);
    if (/remember\s+me/i.test(lab)) { remember = cb; break; }
    const aria = cb.getAttribute("aria-label") || cb.getAttribute("title") || "";
    if (/remember\s+me/i.test(aria)) { remember = cb; break; }
    const near = textOf(cb.parentElement) || "";
    if (/remember\s+me/i.test(near)) { remember = cb; break; }
  }

  let toggle = findByTextRegex('button,[role="button"],a,[role="link"]', /show\s+password|hide\s+password/i);

  if (!toggle) {
    const pwd = document.querySelector('input[type="password"]');
    if (pwd) {
      let container = pwd.parentElement;
      for (let i=0;i<5 && container;i++){
        const btns = Array.from(container.querySelectorAll('button,[role="button"],[data-testid]')).filter(visible);
        if (btns.length) { toggle = btns[0]; break; }
        container = container.parentElement;
      }
    }
  }

  return JSON.stringify({
    forgot: toMatch(forgot),
    remember: toMatch(remember),
    toggle: toMatch(toggle)
  });
}
');
